evaluators.evaluation_logic:
const checkpoints = [];

const shipment_quotes = JSON.parse(localStorage.getItem('shipment_quotes') || '[]');
const shipping_rate_options = JSON.parse(localStorage.getItem('shipping_rate_options') || '[]');
const shipments = JSON.parse(localStorage.getItem('shipments') || '[]');

// Find quotes that match the route and package criteria
const matchingQuotes = shipment_quotes.filter(q => 
  q.origin_city === 'Chicago' &&
  q.origin_postal_code === '60601' &&
  q.origin_country === 'United States' &&
  q.destination_city === 'Paris' &&
  q.destination_postal_code === '75001' &&
  q.destination_country === 'France' &&
  q.package_type === 'box' &&
  q.shipment_type === 'parcel' &&
  Number(q.weight) === 10 &&
  q.weight_unit === 'kg'
);

let candidateQuote = null;
if (matchingQuotes.length > 0) {
  candidateQuote = matchingQuotes.slice().sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
}

// CP1 (0.30): Quote exists and is filtered to delivery within 4 business days, sorted by price low-to-high
let cp1Passed = false;
if (candidateQuote) {
  const hasTimeFilter = candidateQuote.delivery_time_filter_business_days_max != null && candidateQuote.delivery_time_filter_business_days_max <= 4;
  const hasSort = candidateQuote.sort_option === 'price_low_to_high';
  cp1Passed = hasTimeFilter && hasSort;
}
checkpoints.push({ passed: cp1Passed, weight: 0.3 });

// Determine cheapest qualifying rate (<=4 business days) and whether it is selected
let selectedOption = null;
let cp2Passed = false;
if (candidateQuote) {
  const related = shipping_rate_options.filter(r => r.quote_id === candidateQuote.id);
  const limit = candidateQuote.delivery_time_filter_business_days_max != null ? candidateQuote.delivery_time_filter_business_days_max : 4;
  const qualifyingOptions = related.filter(r => {
    const max = r.delivery_estimate_business_days_max;
    const min = r.delivery_estimate_business_days_min;
    return ((max != null && max <= limit) || (min != null && min <= limit));
  });

  selectedOption = related.find(r => r.is_selected);

  if (qualifyingOptions.length > 0 && selectedOption) {
    const cheapest = qualifyingOptions.slice().sort((a, b) => a.price - b.price)[0];
    cp2Passed = selectedOption.id === cheapest.id;
  }
}

// CP2 (0.35): Selected rate option is the cheapest among those delivering within the time limit
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): A shipment was created using the selected cheapest option
let cp3Passed = false;
if (selectedOption) {
  const shipment = shipments.find(s => s.selected_rate_option_id === selectedOption.id);
  if (shipment) {
    cp3Passed = shipment.package_type === 'box' &&
      shipment.shipment_type === 'parcel' &&
      Number(shipment.weight) === 10 &&
      shipment.weight_unit === 'kg';
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const shipment_quotes = JSON.parse(localStorage.getItem('shipment_quotes') || '[]');
const shipping_rate_options = JSON.parse(localStorage.getItem('shipping_rate_options') || '[]');
const shipments = JSON.parse(localStorage.getItem('shipments') || '[]');
const payments = JSON.parse(localStorage.getItem('payments') || '[]');

// Find quotes matching Toronto → New York documents, 3 kg
const matchingQuotes = shipment_quotes.filter(q => 
  q.origin_city === 'Toronto' &&
  q.origin_postal_code === 'M5H 2N2' &&
  q.origin_country === 'Canada' &&
  q.destination_city === 'New York' &&
  q.destination_postal_code === '10019' &&
  q.destination_country === 'United States' &&
  q.package_type === 'documents' &&
  q.shipment_type === 'documents' &&
  Number(q.weight) === 3 &&
  q.weight_unit === 'kg'
);

let candidateQuote = null;
if (matchingQuotes.length > 0) {
  candidateQuote = matchingQuotes.slice().sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
}

// CP1 (0.25): Quote exists with price filter ≤ $40 USD
let cp1Passed = false;
if (candidateQuote) {
  const hasPriceFilter = candidateQuote.price_filter_max != null && candidateQuote.price_filter_max <= 40;
  const hasCurrency = candidateQuote.price_filter_currency === 'usd';
  cp1Passed = hasPriceFilter && hasCurrency;
}
checkpoints.push({ passed: cp1Passed, weight: 0.25 });

// Find selected economy option within price limit
let selectedOption = null;
let cp2Passed = false;
if (candidateQuote) {
  const related = shipping_rate_options.filter(r => r.quote_id === candidateQuote.id);
  selectedOption = related.find(r => r.is_selected);
  if (selectedOption && candidateQuote.price_filter_max != null) {
    const withinLimit = selectedOption.currency === candidateQuote.price_filter_currency && selectedOption.price <= candidateQuote.price_filter_max;
    const isEconomy = selectedOption.service_level === 'economy';
    cp2Passed = withinLimit && isEconomy;
  }
}

// CP2 (0.35): Selected rate option is economy and priced within the configured max price
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.40): Shipment created from that option and paid successfully by credit/debit card
let cp3Passed = false;
if (selectedOption) {
  const shipment = shipments.find(s => s.selected_rate_option_id === selectedOption.id && s.shipment_type === 'documents');
  if (shipment) {
    const payment = payments.find(p => p.shipment_id === shipment.id && p.payment_method === 'credit_debit_card' && p.status === 'succeeded');
    cp3Passed = !!payment;
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const pickup_requests = JSON.parse(localStorage.getItem('pickup_requests') || '[]');
const pickup_time_slots = JSON.parse(localStorage.getItem('pickup_time_slots') || '[]');
const addresses = JSON.parse(localStorage.getItem('addresses') || '[]');

// Determine the upcoming Friday date from available Madrid 28001 slots
const madridSlots = pickup_time_slots.filter(s => 
  s.city === 'Madrid' &&
  s.postal_code === '28001' &&
  s.country === 'Spain' &&
  s.is_available
);

let targetFridayDateStr = null;
if (madridSlots.length > 0) {
  const fridayDates = Array.from(new Set(madridSlots.map(s => {
    const d = new Date(s.date);
    return { iso: d.toISOString().slice(0, 10), weekday: d.getUTCDay() };
  }))).filter(x => x.weekday === 5) // 5 = Friday
    .map(x => x.iso)
    .sort();
  if (fridayDates.length > 0) {
    targetFridayDateStr = fridayDates[0];
  }
}

// Find a pickup request matching criteria
let candidateRequest = null;
if (targetFridayDateStr) {
  const matchingRequests = pickup_requests.filter(p => {
    const addr = addresses.find(a => a.id === p.pickup_address_id);
    const dateStr = p.pickup_date ? new Date(p.pickup_date).toISOString().slice(0, 10) : null;
    return p.pickup_type === 'pre_labeled' &&
      p.has_shipping_labels === true &&
      p.package_count === 4 &&
      Number(p.total_weight) === 25 &&
      p.weight_unit === 'kg' &&
      dateStr === targetFridayDateStr &&
      addr && addr.city === 'Madrid' && addr.postal_code === '28001' && addr.country === 'Spain';
  });
  if (matchingRequests.length > 0) {
    candidateRequest = matchingRequests.slice().sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
  }
}

// CP1 (0.40): Pre-labeled pickup scheduled in Madrid 28001 on upcoming Friday for four packages with total ~25 kg
const cp1Passed = !!candidateRequest;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.60): Chosen time slot is the earliest available slot on that Friday starting at or after 14:00
let cp2Passed = false;
if (candidateRequest && targetFridayDateStr) {
  const slotsThatDay = pickup_time_slots.filter(s => {
    const dateStr = new Date(s.date).toISOString().slice(0, 10);
    return s.city === 'Madrid' &&
      s.postal_code === '28001' &&
      s.country === 'Spain' &&
      s.is_available &&
      dateStr === targetFridayDateStr &&
      s.start_time >= '14:00';
  }).sort((a, b) => {
    const da = new Date(a.date) - new Date(b.date);
    if (da !== 0) return da;
    return (a.start_time < b.start_time ? -1 : a.start_time > b.start_time ? 1 : 0);
  });

  if (slotsThatDay.length > 0) {
    const earliest = slotsThatDay[0];
    cp2Passed = candidateRequest.time_slot_id === earliest.id &&
      candidateRequest.time_slot_start === earliest.start_time &&
      candidateRequest.time_slot_end === earliest.end_time;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const customs_estimates = JSON.parse(localStorage.getItem('customs_estimates') || '[]');
const shipping_rate_options = JSON.parse(localStorage.getItem('shipping_rate_options') || '[]');

// Find customs estimates matching LA → Tokyo clothing, $250 USD, personal gift
const matchingEstimates = customs_estimates.filter(c => 
  c.origin_country === 'United States' &&
  c.origin_city === 'Los Angeles' &&
  c.origin_postal_code === '90001' &&
  c.destination_country === 'Japan' &&
  c.destination_city === 'Tokyo' &&
  c.destination_postal_code === '100-0001' &&
  c.contents_category === 'clothing_apparel' &&
  Number(c.customs_value) === 250 &&
  c.customs_value_currency === 'usd' &&
  c.shipment_purpose === 'personal_gift'
);

let candidateEstimate = null;
if (matchingEstimates.length > 0) {
  candidateEstimate = matchingEstimates.slice().sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
}

// CP1 (0.40): Matching customs estimate exists with duties estimated at ≤ $60
let cp1Passed = false;
if (candidateEstimate) {
  const dutiesOk = typeof candidateEstimate.estimated_duties === 'number' && candidateEstimate.estimated_duties <= 60;
  cp1Passed = dutiesOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.30): Selected rate option supports prepaid duties and has estimated duties ≤ $60, and estimate is marked to include prepaid duties
let cp2Passed = false;
if (candidateEstimate) {
  const selected = shipping_rate_options.find(r => r.id === candidateEstimate.selected_rate_option_id);
  if (selected) {
    const supportsPrepaid = selected.supports_prepaid_duties === true;
    const dutiesOk = typeof selected.estimated_duties === 'number' && selected.estimated_duties <= 60;
    const currencyOk = selected.estimated_duties_currency === candidateEstimate.customs_value_currency;
    const includePrepaid = candidateEstimate.include_prepaid_duties === true;
    cp2Passed = supportsPrepaid && dutiesOk && currencyOk && includePrepaid;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

// CP3 (0.30): That customs estimate has been saved
let cp3Passed = false;
if (candidateEstimate) {
  cp3Passed = candidateEstimate.saved === true;
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const saved_locations = JSON.parse(localStorage.getItem('saved_locations') || '[]');

// Locations that match the task criteria
const candidateLocations = locations.filter(loc => 
  loc.city === 'Berlin' &&
  loc.postal_code === '10117' &&
  loc.country === 'Germany' &&
  loc.location_type === 'drop_off' &&
  loc.accepts_international_shipments === true &&
  typeof loc.weekday_close_time === 'string' &&
  loc.weekday_close_time >= '20:00'
);

// In this model, distance is effectively equal, so treat first matching as nearest
const nearestLocation = candidateLocations.length > 0 ? candidateLocations[0] : null;

// Saved locations that correspond to any qualifying location
const qualifyingSaved = saved_locations.filter(sl => candidateLocations.some(loc => loc.id === sl.location_id));

// CP1 (0.60): User saved at least one location that matches all criteria
const cp1Passed = qualifyingSaved.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.40): Among qualifying locations, the saved one includes the nearest candidate
let cp2Passed = false;
if (nearestLocation) {
  cp2Passed = qualifyingSaved.some(sl => sl.location_id === nearestLocation.id);
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const shipments = JSON.parse(localStorage.getItem('shipments') || '[]');
const delivery_time_slots = JSON.parse(localStorage.getItem('delivery_time_slots') || '[]');
const delivery_reschedule_requests = JSON.parse(localStorage.getItem('delivery_reschedule_requests') || '[]');

// Find the in-transit shipment with the known tracking number
const baseShipment = shipments.find(s => s.tracking_number === 'ZX123456789US' && s.status === 'in_transit');

let expectedDateStr = null;
let expectedSlot = null;
if (baseShipment) {
  const slots = delivery_time_slots
    .filter(slot => slot.shipment_id === baseShipment.id && slot.is_available)
    .sort((a, b) => {
      const da = new Date(a.date) - new Date(b.date);
      if (da !== 0) return da;
      return (a.start_time < b.start_time ? -1 : a.start_time > b.start_time ? 1 : 0);
    });

  const uniqueDates = Array.from(new Set(slots.map(s => new Date(s.date).toISOString().slice(0, 10)))).sort();
  if (uniqueDates.length >= 3) {
    expectedDateStr = uniqueDates[2]; // third available date
    const eveningSlots = slots.filter(s => {
      const dStr = new Date(s.date).toISOString().slice(0, 10);
      return dStr === expectedDateStr && s.start_time === '18:00' && s.end_time === '21:00';
    });
    if (eveningSlots.length > 0) {
      expectedSlot = eveningSlots[0];
    }
  }
}

// Find latest reschedule request for this shipment
let latestRequest = null;
if (baseShipment) {
  const reqs = delivery_reschedule_requests.filter(r => r.shipment_id === baseShipment.id);
  if (reqs.length > 0) {
    latestRequest = reqs.slice().sort((a, b) => new Date(b.requested_at) - new Date(a.requested_at))[0];
  }
}

// CP1 (0.60): There is a reschedule request for the shipment to the third available date with 18:00–21:00 window
let cp1Passed = false;
if (latestRequest && expectedDateStr && expectedSlot) {
  const newDateStr = latestRequest.new_delivery_date ? new Date(latestRequest.new_delivery_date).toISOString().slice(0, 10) : null;
  cp1Passed = newDateStr === expectedDateStr &&
    latestRequest.new_time_window_start === '18:00' &&
    latestRequest.new_time_window_end === '21:00';
}
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.40): Shipment record updated to the same new date and evening time window
let cp2Passed = false;
if (baseShipment && expectedDateStr) {
  const updatedShipment = shipments.find(s => s.id === baseShipment.id);
  if (updatedShipment && updatedShipment.delivery_estimated_date) {
    const shipDateStr = new Date(updatedShipment.delivery_estimated_date).toISOString().slice(0, 10);
    cp2Passed = shipDateStr === expectedDateStr &&
      updatedShipment.delivery_time_window_start === '18:00' &&
      updatedShipment.delivery_time_window_end === '21:00';
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const shipments = JSON.parse(localStorage.getItem('shipments') || '[]');
const addresses = JSON.parse(localStorage.getItem('addresses') || '[]');
const shipping_services = JSON.parse(localStorage.getItem('shipping_services') || '[]');
const payments = JSON.parse(localStorage.getItem('payments') || '[]');

// Candidate draft shipments with $500 declared value and full insurance
const draftCandidates = shipments.filter(s => 
  s.status === 'draft' &&
  Number(s.declared_value) === 500 &&
  s.declared_value_currency === 'usd' &&
  s.insurance_type === 'full_value' &&
  s.insurance_included === true
);

function matchesRouteAndService(ship) {
  const origin = addresses.find(a => a.id === ship.origin_address_id);
  const dest = addresses.find(a => a.id === ship.destination_address_id);
  const svc = shipping_services.find(svc => svc.id === ship.service_id);
  const originOk = origin && origin.address_type === 'business' && origin.city === 'Shanghai' && origin.postal_code === '200001' && origin.country === 'China';
  const destOk = dest && dest.city === 'London' && dest.country === 'United Kingdom';
  const serviceOk = svc && (svc.service_level === 'express' || svc.service_level === 'priority');
  return originOk && destOk && serviceOk;
}

const matchingDrafts = draftCandidates.filter(matchesRouteAndService);
let candidateShipment = null;
if (matchingDrafts.length > 0) {
  candidateShipment = matchingDrafts.slice().sort((a, b) => new Date(b.updated_at || b.created_at) - new Date(a.updated_at || a.created_at))[0];
}

// CP1 (0.60): Draft shipment exists matching Shanghai business sender → London recipient, express/priority, $500 full insurance
const cp1Passed = !!candidateShipment;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.40): No successful payment exists for this shipment (still a draft, not purchased)
let cp2Passed = false;
if (candidateShipment) {
  const succeededPayment = payments.find(p => p.shipment_id === candidateShipment.id && p.status === 'succeeded');
  cp2Passed = !succeededPayment;
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const shipment_quotes = JSON.parse(localStorage.getItem('shipment_quotes') || '[]');
const shipping_rate_options = JSON.parse(localStorage.getItem('shipping_rate_options') || '[]');

// Quotes matching Amsterdam → Sydney 2 kg box
const matchingQuotes = shipment_quotes.filter(q => 
  q.origin_city === 'Amsterdam' &&
  q.origin_postal_code === '1012 AB' &&
  q.origin_country === 'Netherlands' &&
  q.destination_city === 'Sydney' &&
  q.destination_postal_code === '2000' &&
  q.destination_country === 'Australia' &&
  q.package_type === 'box' &&
  q.shipment_type === 'parcel' &&
  Number(q.weight) === 2 &&
  q.weight_unit === 'kg'
);

let candidateQuote = null;
if (matchingQuotes.length > 0) {
  candidateQuote = matchingQuotes.slice().sort((a, b) => new Date(b.created_at) - new Date(a.created_at))[0];
}

// CP1 (0.40): Quote exists with price ≤ $100, CO2 ≤ 15 kg, sorted by fastest delivery
let cp1Passed = false;
if (candidateQuote) {
  const priceOk = candidateQuote.price_filter_max != null && candidateQuote.price_filter_max <= 100 && candidateQuote.price_filter_currency === 'usd';
  const co2Ok = candidateQuote.co2_filter_max_kg != null && candidateQuote.co2_filter_max_kg <= 15;
  const sortOk = candidateQuote.sort_option === 'fastest_delivery';
  cp1Passed = priceOk && co2Ok && sortOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

// CP2 (0.60): Selected rate option is the fastest among those within price and CO2 limits
let cp2Passed = false;
if (candidateQuote) {
  const related = shipping_rate_options.filter(r => r.quote_id === candidateQuote.id);
  const qualifying = related.filter(r => {
    // Price filter
    if (candidateQuote.price_filter_max != null) {
      if (r.currency !== candidateQuote.price_filter_currency) return false;
      if (r.price > candidateQuote.price_filter_max) return false;
    }
    // CO2 filter
    if (candidateQuote.co2_filter_max_kg != null) {
      if (r.co2_kg == null || r.co2_kg > candidateQuote.co2_filter_max_kg) return false;
    }
    return true;
  });

  const selected = related.find(r => r.is_selected);

  if (qualifying.length > 0 && selected) {
    const sorted = qualifying.slice().sort((a, b) => {
      const aMax = a.delivery_estimate_business_days_max ?? 1e9;
      const bMax = b.delivery_estimate_business_days_max ?? 1e9;
      if (aMax !== bMax) return aMax - bMax;
      const aMin = a.delivery_estimate_business_days_min ?? aMax;
      const bMin = b.delivery_estimate_business_days_min ?? bMax;
      if (aMin !== bMin) return aMin - bMin;
      return a.price - b.price;
    });
    const fastest = sorted[0];
    cp2Passed = fastest && selected.id === fastest.id;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
